+// =============================================================================
+// HYBRID Q2_K + SPARSE OUTLIER KERNELS (Zell v2.0)
+// =============================================================================
+// These kernels enable 30 TPS inference by:
+// 1. Using Q2_K (2.96 bpw) for base weights - fits in RAM (14.8 GB)
+// 2. Adding FP16 sparse corrections for top 1% outliers
+// Formula: y = Q2K_matmul(x, W_q2k) + sparse_correction(x, outliers)
+
+/// Q2_K Block Structure: 256 values in 84 bytes
+/// Layout: [f16 d][f16 dmin][48 scales][64 qs]
+struct block_q2_K {
+    half d;           // Super-block scale
+    half dmin;        // Super-block min
+    uchar scales[48]; // Per-group scales (16 groups, 4-bit each, packed)
+    uchar qs[64];     // 2-bit quantized values (256 values, 4 per byte)
+};
+
+/// Fused Q2_K expert FFN with SPARSE OUTLIER correction
+/// Gate/Up: y_base = Q2K(x) + sparse_outlier_correction(x)
+/// Each threadgroup (32 threads) computes one output row
+kernel void moe_expert_ffn_q2k_sparse(
+    device const float *x [[buffer(0)]],              // [batch_size, n_embd] - input
+    device const uchar *gate_q2k [[buffer(1)]],       // [n_ff, n_embd] Q2_K row-major
+    device const uchar *up_q2k [[buffer(2)]],         // [n_ff, n_embd] Q2_K row-major
+    device const uchar *down_q2k [[buffer(3)]],       // [n_embd, n_ff] Q2_K (unused here)
+    device float *gate_buf [[buffer(4)]],             // [batch_size, n_ff] - intermediate
+    device float *up_buf [[buffer(5)]],               // unused
+    device float *out [[buffer(6)]],                  // unused in this kernel
+    constant uint &batch_size [[buffer(7)]],
+    constant uint &n_embd [[buffer(8)]],
+    constant uint &n_ff [[buffer(9)]],
+    constant uint &batch_offset [[buffer(10)]],
+    constant uint *token_indices [[buffer(11)]],      // Indirection for non-contiguous tokens
+    // Sparse outlier buffers for GATE
+    device const uint *gate_row_ptr [[buffer(12)]],   // CSR row pointers [n_ff + 1]
+    device const ushort *gate_col_idx [[buffer(13)]], // CSR column indices
+    device const half *gate_values [[buffer(14)]],    // FP16 outlier values
+    // Sparse outlier buffers for UP
+    device const uint *up_row_ptr [[buffer(15)]],
+    device const ushort *up_col_idx [[buffer(16)]],
+    device const half *up_values [[buffer(17)]],
+    uint3 tgpig [[threadgroup_position_in_grid]],     // (local_batch_idx, row_idx, 0)
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    const int local_idx = tgpig.x;
+    const int row_idx = tgpig.y;  // output neuron (0 to n_ff-1)
+
+    if (local_idx >= batch_size || row_idx >= n_ff) return;
+
+    const int actual_token_idx = (token_indices != nullptr) ? token_indices[local_idx] : (local_idx + batch_offset);
+    const int batch_idx = actual_token_idx;
+
+    // Q2_K: 84 bytes per 256 values
+    const int blocks_per_row = (n_embd + 255) / 256;
+    const int row_stride_bytes = blocks_per_row * 84;
+
+    device const block_q2_K *gate_row = (device const block_q2_K *)(gate_q2k + row_idx * row_stride_bytes);
+    device const block_q2_K *up_row = (device const block_q2_K *)(up_q2k + row_idx * row_stride_bytes);
+
+    float gate_sum = 0.0f;
+    float up_sum = 0.0f;
+    const int batch_input_offset = batch_idx * n_embd;
+
+    // === PHASE 1: Q2_K Base Matmul ===
+    // Each thread processes different blocks (SIMD parallelism)
+    for (int block_idx = tiisg; block_idx < blocks_per_row; block_idx += 32) {
+        device const block_q2_K *gb = gate_row + block_idx;
+        device const block_q2_K *ub = up_row + block_idx;
+
+        const float gd = (float)gb->d;
+        const float gdmin = (float)gb->dmin;
+        const float ud = (float)ub->d;
+        const float udmin = (float)ub->dmin;
+
+        const int input_base = batch_input_offset + block_idx * 256;
+
+        // Process 256 values (64 bytes of qs, 4 values per byte)
+        for (int i = 0; i < 256; i++) {
+            const int byte_idx = i / 4;
+            const int bit_offset = (i % 4) * 2;
+
+            // Extract 2-bit quantized value
+            const uint gq = (gb->qs[byte_idx] >> bit_offset) & 0x3;
+            const uint uq = (ub->qs[byte_idx] >> bit_offset) & 0x3;
+
+            // Get per-group scale (16 groups of 16 values each)
+            const uint scale_idx = i / 16;
+            const uint scale_byte_idx = scale_idx / 2;
+            const uint gscale = (scale_idx % 2 == 0) ?
+                (gb->scales[scale_byte_idx] & 0xF) : (gb->scales[scale_byte_idx] >> 4);
+            const uint uscale = (scale_idx % 2 == 0) ?
+                (ub->scales[scale_byte_idx] & 0xF) : (ub->scales[scale_byte_idx] >> 4);
+
+            // Dequantize: val = d * scale * q - dmin * scale
+            const float gw = gd * (float)gscale * (float)gq - gdmin * (float)gscale;
+            const float uw = ud * (float)uscale * (float)uq - udmin * (float)uscale;
+
+            const float xv = x[input_base + i];
+            gate_sum += gw * xv;
+            up_sum += uw * xv;
+        }
+    }
+
+    // SIMD reduction for base Q2_K contribution
+    gate_sum = simd_sum(gate_sum);
+    up_sum = simd_sum(up_sum);
+
+    // === PHASE 2: Sparse Outlier Correction (FP16) ===
+    // Only first thread applies sparse corrections (sequential but sparse)
+    if (tiisg == 0) {
+        // Gate sparse correction
+        if (gate_row_ptr != nullptr) {
+            const uint gate_start = gate_row_ptr[row_idx];
+            const uint gate_end = gate_row_ptr[row_idx + 1];
+            for (uint i = gate_start; i < gate_end; i++) {
+                const uint col = gate_col_idx[i];
+                const float val = (float)gate_values[i];
+                gate_sum += val * x[batch_input_offset + col];
+            }
+        }
+
+        // Up sparse correction
+        if (up_row_ptr != nullptr) {
+            const uint up_start = up_row_ptr[row_idx];
+            const uint up_end = up_row_ptr[row_idx + 1];
+            for (uint i = up_start; i < up_end; i++) {
+                const uint col = up_col_idx[i];
+                const float val = (float)up_values[i];
+                up_sum += val * x[batch_input_offset + col];
+            }
+        }
+
+        // Apply SwiGLU: SiLU(gate) * up
+        float silu = gate_sum / (1.0f + exp(-gate_sum));
+        float activated = silu * up_sum;
+        const int output_idx = batch_idx * n_ff + row_idx;
+        gate_buf[output_idx] = activated;
+    }
+}
+
+/// Down projection Q2_K with SPARSE OUTLIER correction
+kernel void moe_down_proj_q2k_sparse(
+    device const uchar *down_q2k [[buffer(0)]],       // [n_embd, n_ff] Q2_K
+    device const float *activated [[buffer(1)]],      // [batch_size, n_ff]
+    device float *output [[buffer(2)]],               // [batch_size, n_embd]
+    constant uint &batch_size [[buffer(3)]],
+    constant uint &n_embd [[buffer(4)]],
+    constant uint &n_ff [[buffer(5)]],
+    constant uint &batch_offset [[buffer(6)]],
+    constant uint *token_indices [[buffer(7)]],
+    // Sparse outlier buffers
+    device const uint *row_ptr [[buffer(8)]],         // CSR row pointers [n_embd + 1]
+    device const ushort *col_idx [[buffer(9)]],       // CSR column indices
+    device const half *values [[buffer(10)]],         // FP16 outlier values
+    uint3 tgpig [[threadgroup_position_in_grid]],
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    const int local_idx = tgpig.x;
+    const int row_idx = tgpig.y;
+
+    if (local_idx >= batch_size || row_idx >= n_embd) return;
+
+    const int actual_token_idx = (token_indices != nullptr) ? token_indices[local_idx] : (local_idx + batch_offset);
+    const int batch_idx = actual_token_idx;
+
+    // Q2_K: 84 bytes per 256 values
+    const int blocks_per_row = (n_ff + 255) / 256;
+    const int row_stride_bytes = blocks_per_row * 84;
+
+    device const block_q2_K *row_blocks = (device const block_q2_K *)(down_q2k + row_idx * row_stride_bytes);
+
+    float sum = 0.0f;
+    const int batch_activated_offset = batch_idx * n_ff;
+
+    // === PHASE 1: Q2_K Base Matmul ===
+    for (int block_idx = tiisg; block_idx < blocks_per_row; block_idx += 32) {
+        device const block_q2_K *b = row_blocks + block_idx;
+
+        const float d = (float)b->d;
+        const float dmin = (float)b->dmin;
+        const int offset = batch_activated_offset + block_idx * 256;
+
+        for (int i = 0; i < 256 && (block_idx * 256 + i) < n_ff; i++) {
+            const int byte_idx = i / 4;
+            const int bit_offset = (i % 4) * 2;
+            const uint q = (b->qs[byte_idx] >> bit_offset) & 0x3;
+
+            const uint scale_idx = i / 16;
+            const uint scale_byte_idx = scale_idx / 2;
+            const uint scale = (scale_idx % 2 == 0) ?
+                (b->scales[scale_byte_idx] & 0xF) : (b->scales[scale_byte_idx] >> 4);
+
+            const float w = d * (float)scale * (float)q - dmin * (float)scale;
+            sum += activated[offset + i] * w;
+        }
+    }
+
+    // SIMD reduction
+    sum = simd_sum(sum);
+
+    // === PHASE 2: Sparse Outlier Correction ===
+    if (tiisg == 0) {
+        if (row_ptr != nullptr) {
+            const uint start = row_ptr[row_idx];
+            const uint end = row_ptr[row_idx + 1];
+            for (uint i = start; i < end; i++) {
+                const uint col = col_idx[i];
+                const float val = (float)values[i];
+                sum += val * activated[batch_activated_offset + col];
+            }
+        }
+
+        const int output_idx = batch_idx * n_embd + row_idx;
+        output[output_idx] = sum;
+    }
+}
+
+/// Pure Q2_K matvec (without sparse correction) for benchmarking
+/// Each threadgroup (32 threads) computes one output row
+kernel void moe_matvec_q2k_simd(
+    device const uchar *weights_q2k [[buffer(0)]],    // Q2_K weights [m, n]
+    device const float *input [[buffer(1)]],          // Input vector [n]
+    device float *output [[buffer(2)]],               // Output vector [m]
+    constant uint &nb00 [[buffer(3)]],                // Row stride in bytes
+    constant uint &ne00 [[buffer(4)]],                // Row size in elements (must be multiple of 256)
+    uint3 tgpig [[threadgroup_position_in_grid]],
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    const int row_idx = tgpig.x;
+    const int row_offset = row_idx * nb00;
+
+    device const block_q2_K *current_block = (device const block_q2_K *)(weights_q2k + row_offset);
+
+    float sum = 0.0f;
+    const int num_blocks = ne00 / 256;
+
+    for (int block_idx = tiisg; block_idx < num_blocks; block_idx += 32) {
+        device const block_q2_K *b = current_block + block_idx;
+        const float d = (float)b->d;
+        const float dmin = (float)b->dmin;
+        const int input_offset = block_idx * 256;
+
+        float block_sum = 0.0f;
+
+        for (int i = 0; i < 256; i++) {
+            const int byte_idx = i / 4;
+            const int bit_offset = (i % 4) * 2;
+            const uint q = (b->qs[byte_idx] >> bit_offset) & 0x3;
+
+            const uint scale_idx = i / 16;
+            const uint scale_byte_idx = scale_idx / 2;
+            const uint scale = (scale_idx % 2 == 0) ?
+                (b->scales[scale_byte_idx] & 0xF) : (b->scales[scale_byte_idx] >> 4);
+
+            const float w = d * (float)scale * (float)q - dmin * (float)scale;
+            block_sum += w * input[input_offset + i];
+        }
+
+        sum += block_sum;
+    }
+
+    sum = simd_sum(sum);
+
+    if (tiisg == 0) {
+        output[row_idx] = sum;
+    }
+}
